class DataProcessor {
    public data: int[]
    public weights: int[]
    protected threshold: int
    private _processed: int = 0
    private _skipped: int = 0
    static totalProcessed: int = 0

    constructor(data: int[], weights: int[], threshold: int) {
        this.data = data
        this.weights = weights
        this.threshold = threshold
    }

    isValid(idx: int): bool {
        return idx < this.data.length && this.data[idx] >= 0 && idx < this.weights.length
    }

    computeItem(idx: int): int {
        return this.data[idx] * this.weights[idx] - this.threshold
    }

    process(): int {
        val total = 0
        val i = 0
        while (i < this.data.length) {
            if (!this.isValid(i)) {
                this._skipped = this._skipped + 1
                i = i + 1
                continue
            }
            val item = this.computeItem(i)
            if (item < 0 && this.threshold > 0) {
                i = i + 1
                continue
            }
            total = total + item
            this._processed = this._processed + 1
            DataProcessor.totalProcessed = DataProcessor.totalProcessed + 1
            if (this._processed >= this.data.length * 2) {
                break
            }
            i = i + 1
        }
        return total
    }

    getStats(): int {
        return this._processed * this.threshold - this._skipped * this.weights[0] + DataProcessor.totalProcessed
    }
}

class PipelineProcessor extends DataProcessor {
    public stages: int[]
    public maxStages: int
    private _stageResults: int[]
    protected multiplier: int
    static pipelineRuns: int = 0

    constructor(data: int[], weights: int[], threshold: int, stages: int[], multiplier: int) {
        super(data, weights, threshold)
        this.stages = stages
        this.maxStages = stages.length
        this.multiplier = multiplier
        this._stageResults = stages
    }

    runStage(stageIdx: int, input: int): int {
        if (stageIdx >= this.maxStages || !this.isValid(stageIdx)) {
            return input
        }
        val stageWeight = this.stages[stageIdx] * this.weights[stageIdx] - this.threshold
        return input * stageWeight - this.computeItem(stageIdx) + this.multiplier
    }

    runPipeline(): int {
        PipelineProcessor.pipelineRuns = PipelineProcessor.pipelineRuns + 1
        val result = this.process()
        val i = 0
        while (i < this.maxStages && i < this.data.length) {
            val stageResult = this.runStage(i, result)
            if (stageResult < 0 && this.threshold > 0) {
                this._stageResults[i] = 0
                i = i + 1
                continue
            }
            this._stageResults[i] = stageResult
            val k = 0
            for (val k = 0; k < i && k < this.maxStages; k = k + 1) {
                val prev = this._stageResults[k] * this.multiplier - stageResult
                if (prev > this.threshold * this.maxStages) {
                    this._stageResults[k] = prev
                    if (this._stageResults[k] > this.threshold * this.data.length) {
                        break
                    }
                } else {
                    this._stageResults[k] = this._stageResults[k] + stageResult
                }
            }
            result = stageResult + this.getStats()
            i = i + 1
            if (result > this.threshold * this.maxStages * this.multiplier) {
                break
            }
        }
        return result
    }

    getFinalScore(): int {
        val pipeScore = this.runPipeline() * this.multiplier
        val stageSum = this._stageResults[0] * this.stages[0] - this._stageResults[this.maxStages - 1]
        val statsFactor = this.getStats() * PipelineProcessor.pipelineRuns - DataProcessor.totalProcessed
        return pipeScore + stageSum - statsFactor + this.process()
    }
}

